/* test/test.mjs — Unified test suite for the taint analysis engine.
   Covers positive detections, negative (safe) patterns, and baseline library scans. */

import { readFileSync, readdirSync, existsSync } from 'fs';
import { resolve, dirname } from 'path';
import { fileURLToPath } from 'url';
import { analyze, analyzeMultiple } from './harness.mjs';

const __dirname = dirname(fileURLToPath(import.meta.url));
const libsDir = resolve(__dirname, 'libs');
const cveDir = resolve(__dirname, 'cve');
const bundlesDir = resolve(__dirname, 'bundles');
const jquerySrc = readFileSync(resolve(libsDir, 'jquery.min.js'), 'utf8');

// Helper: load a file if it exists, return null otherwise (for optional CVE/bundle files)
function tryReadFile(path) {
  try { return readFileSync(path, 'utf8'); } catch { return null; }
}

let passed = 0, failed = 0;

function test(name, fn) {
  try {
    fn();
    passed++;
    console.log(`  PASS  ${name}`);
  } catch (e) {
    failed++;
    console.log(`  FAIL  ${name}`);
    console.log(`        ${e.message}`);
  }
}

function expect(findings) {
  const obj = {
    toHaveType(type) {
      const found = findings.some(f => f.type === type);
      if (!found) throw new Error(`Expected finding of type "${type}" but got: [${findings.map(f => f.type).join(', ') || 'none'}]`);
    },
    toHaveCount(n) {
      if (findings.length !== n) throw new Error(`Expected ${n} findings, got ${findings.length}: [${findings.map(f => f.type + ':' + f.title).join('; ')}]`);
    },
    toHaveAtLeast(n) {
      if (findings.length < n) throw new Error(`Expected at least ${n} findings, got ${findings.length}`);
    },
    toBeEmpty() {
      if (findings.length > 0) throw new Error(`Expected no findings, got ${findings.length}: [${findings.map(f => f.type + ': ' + f.title).join('; ')}]`);
    },
    notToHaveType(type) {
      const found = findings.some(f => f.type === type);
      if (found) throw new Error(`Expected no "${type}" finding but got one: ${findings.filter(f => f.type === type).map(f => f.title).join('; ')}`);
    },
    toHaveFingerprint(fp) {
      const found = findings.some(f => f.sink?.fingerprint === fp);
      if (!found) throw new Error(`Expected finding at ${fp} but got: [${findings.map(f => f.sink?.fingerprint).join(', ') || 'none'}]`);
    },
    notToHaveFingerprint(fp) {
      const found = findings.some(f => f.sink?.fingerprint === fp);
      if (found) throw new Error(`Expected no finding at ${fp} but one exists`);
    },
    get not() {
      return {
        toHaveType(type) { obj.notToHaveType(type); },
      };
    },
  };
  return obj;
}

// General-purpose assertion helpers for data-flow-aware PoC checks
function assert(cond, msg) { if (!cond) throw new Error(msg); }
function assertEq(a, b, msg) { if (a !== b) throw new Error(msg || `Expected ${JSON.stringify(b)}, got ${JSON.stringify(a)}`); }
function assertIncludes(str, sub, msg) { if (typeof str !== 'string' || !str.includes(sub)) throw new Error(msg || `Expected string containing ${JSON.stringify(sub)}, got ${JSON.stringify(str)}`); }
function assertMatch(str, re, msg) { if (typeof str !== 'string' || !re.test(str)) throw new Error(msg || `Expected string matching ${re}, got ${JSON.stringify(str)}`); }
function assertHasTransform(transforms, op, args) {
  assert(Array.isArray(transforms), `Expected transforms array, got ${JSON.stringify(transforms)}`);
  const match = transforms.some(t => t.op === op && (args === undefined || JSON.stringify(t.args) === JSON.stringify(args)));
  if (!match) throw new Error(`Expected transform {op:${JSON.stringify(op)}${args !== undefined ? ',args:'+JSON.stringify(args) : ''}} in ${JSON.stringify(transforms.map(t=>({op:t.op,args:t.args})))}`);
}

// Helper: analyze app code with the real jQuery library loaded
function analyzeWithJQuery(appCode) {
  return analyzeMultiple([
    { source: jquerySrc, file: 'jquery.min.js' },
    { source: appCode, file: 'app.js' },
  ]);
}

